 22→	// --- identity
 23→
 24→	/**
 25→	 * Compares two uris.
 26→	 *
 27→	 * @param uri1 Uri
 28→	 * @param uri2 Uri
 29→	 * @param ignoreFragment Ignore the fragment (defaults to `false`)
 30→	 */
 31→	compare(uri1: URI, uri2: URI, ignoreFragment?: boolean): number;
