130→/**
131→ * Returns as soon as one of the promises resolves or rejects and cancels remaining promises
132→ */
133→export function raceCancellablePromises<T>(cancellablePromises: (CancelablePromise<T> | Promise<T>)[]): CancelablePromise<T> {
134→	let resolvedPromiseIndex = -1;
135→	const promises = cancellablePromises.map((promise, index) => promise.then(result => { resolvedPromiseIndex = index; return result; }));
136→	const promise = Promise.race(promises) as CancelablePromise<T>;
137→	promise.cancel = () => {
138→		cancellablePromises.forEach((cancellablePromise, index) => {
139→			if (index !== resolvedPromiseIndex && (cancellablePromise as CancelablePromise<T>).cancel) {
140→				(cancellablePromise as CancelablePromise<T>).cancel();
141→			}
142→		});
143→	};
144→	promise.finally(() => {
145→		promise.cancel();
146→	});
147→	return promise;
148→}
