164→export function asPromise<T>(callback: () => T | Thenable<T>): Promise<T> {
165→	return new Promise<T>((resolve, reject) => {
166→		const item = callback();
167→		if (isThenable<T>(item)) {
168→			item.then(resolve, reject);
169→		} else {
