198→/**
199→ * A helper to prevent accumulation of sequential async tasks.
200→ *
201→ * Imagine a mail man with the sole task of delivering letters. As soon as
202→ * a letter submitted for delivery, he drives to the destination, delivers it
203→ * and returns to his base. Imagine that during the trip, N more letters were submitted.
204→ * When the mail man returns, he picks those N letters and delivers them all in a
205→ * single trip. Even though N+1 submissions occurred, only 2 deliveries were made.
206→ *
207→ * The throttler implements this via the queue() method, by providing it a task
208→ * factory. Following the example:
209→ *
210→ * 		const throttler = new Throttler();
211→ * 		const letters = [];
212→ *
213→ * 		function deliver() {
214→ * 			const lettersToDeliver = letters;
215→ * 			letters = [];
216→ * 			return makeTheTrip(lettersToDeliver);
217→ * 		}
218→ *
219→ * 		function onLetterReceived(l) {
220→ * 			letters.push(l);
221→ * 			throttler.queue(deliver);
222→ * 		}
223→ */
224→export class Throttler implements IDisposable {
225→
226→	private activePromise: Promise<any> | null;
227→	private queuedPromise: Promise<any> | null;
228→	private queuedPromiseFactory: ICancellableTask<Promise<any>> | null;
229→	private cancellationTokenSource: CancellationTokenSource;
230→
231→	constructor() {
232→		this.activePromise = null;
233→		this.queuedPromise = null;
234→		this.queuedPromiseFactory = null;
235→
236→		this.cancellationTokenSource = new CancellationTokenSource();
237→	}
238→
239→	queue<T>(promiseFactory: ICancellableTask<Promise<T>>): Promise<T> {
240→		if (this.cancellationTokenSource.token.isCancellationRequested) {
241→			return Promise.reject(new Error('Throttler is disposed'));
242→		}
243→
244→		if (this.activePromise) {
245→			this.queuedPromiseFactory = promiseFactory;
246→
247→			if (!this.queuedPromise) {
248→				const onComplete = () => {
249→					this.queuedPromise = null;
250→
251→					if (this.cancellationTokenSource.token.isCancellationRequested) {
252→						return;
253→					}
254→
255→					const result = this.queue(this.queuedPromiseFactory!);
256→					this.queuedPromiseFactory = null;
257→
258→					return result;
259→				};
260→
261→				this.queuedPromise = new Promise(resolve => {
262→					this.activePromise!.then(onComplete, onComplete).then(resolve);
263→				});
264→			}
265→
266→			return new Promise((resolve, reject) => {
267→				this.queuedPromise!.then(resolve, reject);
268→			});
269→		}
270→
271→		this.activePromise = promiseFactory(this.cancellationTokenSource.token);
272→
273→		return new Promise((resolve, reject) => {
274→			this.activePromise!.then((result: T) => {
275→				this.activePromise = null;
276→				resolve(result);
277→			}, (err: unknown) => {
278→				this.activePromise = null;
279→				reject(err);
280→			});
281→		});
282→	}
283→
284→	dispose(): void {
285→		this.cancellationTokenSource.cancel();
286→	}
287→}
