298→export class SequencerByKey<TKey> {
299→
300→	private promiseMap = new Map<TKey, Promise<unknown>>();
301→
302→	queue<T>(key: TKey, promiseTask: ITask<Promise<T>>): Promise<T> {
303→		const runningPromise = this.promiseMap.get(key) ?? Promise.resolve();
304→		const newPromise = runningPromise
305→			.catch(() => { })
306→			.then(promiseTask)
307→			.finally(() => {
308→				if (this.promiseMap.get(key) === newPromise) {
309→					this.promiseMap.delete(key);
310→				}
311→			});
312→		this.promiseMap.set(key, newPromise);
313→		return newPromise;
314→	}
315→
316→	peek(key: TKey): Promise<unknown> | undefined {
317→		return this.promiseMap.get(key) || undefined;
318→	}
319→
320→	keys(): IterableIterator<TKey> {
321→		return this.promiseMap.keys();
322→	}
323→}
