359→/**
360→ * A helper to delay (debounce) execution of a task that is being requested often.
361→ *
362→ * Following the throttler, now imagine the mail man wants to optimize the number of
363→ * trips proactively. The trip itself can be long, so he decides not to make the trip
364→ * as soon as a letter is submitted. Instead he waits a while, in case more
365→ * letters are submitted. After said waiting period, if no letters were submitted, he
366→ * decides to make the trip. Imagine that N more letters were submitted after the first
367→ * one, all within a short period of time between each other. Even though N+1
368→ * submissions occurred, only 1 delivery was made.
369→ *
370→ * The delayer offers this behavior via the trigger() method, into which both the task
371→ * to be executed and the waiting period (delay) must be passed in as arguments. Following
372→ * the example:
373→ *
374→ * 		const delayer = new Delayer(WAITING_PERIOD);
375→ * 		const letters = [];
376→ *
377→ * 		function letterReceived(l) {
378→ * 			letters.push(l);
379→ * 			delayer.trigger(() => { return makeTheTrip(); });
380→ * 		}
381→ */
382→export class Delayer<T> implements IDisposable {
383→
384→	private deferred: IScheduledLater | null;
385→	private completionPromise: Promise<any> | null;
386→	private doResolve: ((value?: any | Promise<any>) => void) | null;
387→	private doReject: ((err: unknown) => void) | null;
388→	private task: ITask<T | Promise<T>> | null;
389→
390→	constructor(public defaultDelay: number | typeof MicrotaskDelay) {
391→		this.deferred = null;
392→		this.completionPromise = null;
393→		this.doResolve = null;
394→		this.doReject = null;
395→		this.task = null;
396→	}
397→
398→	trigger(task: ITask<T | Promise<T>>, delay = this.defaultDelay): Promise<T> {
399→		this.task = task;
400→		this.cancelTimeout();
401→
402→		if (!this.completionPromise) {
403→			this.completionPromise = new Promise((resolve, reject) => {
404→				this.doResolve = resolve;
405→				this.doReject = reject;
406→			}).then(() => {
407→				this.completionPromise = null;
408→				this.doResolve = null;
409→				if (this.task) {
410→					const task = this.task;
411→					this.task = null;
412→					return task();
413→				}
414→				return undefined;
415→			});
416→		}
417→
418→		const fn = () => {
419→			this.deferred = null;
420→			this.doResolve?.(null);
421→		};
422→
423→		this.deferred = delay === MicrotaskDelay ? microtaskDeferred(fn) : timeoutDeferred(delay, fn);
424→
425→		return this.completionPromise;
426→	}
427→
428→	isTriggered(): boolean {
429→		return !!this.deferred?.isTriggered();
430→	}
431→
432→	cancel(): void {
433→		this.cancelTimeout();
434→
435→		if (this.completionPromise) {
436→			this.doReject?.(new CancellationError());
437→			this.completionPromise = null;
438→		}
439→	}
440→
441→	private cancelTimeout(): void {
442→		this.deferred?.dispose();
443→		this.deferred = null;
444→	}
445→
446→	dispose(): void {
447→		this.cancel();
448→	}
449→}
450→
451→/**
452→ * A helper to delay execution of a task that is being requested often, while
453→ * preventing accumulation of consecutive executions, while the task runs.
454→ *
455→ * The mail man is clever and waits for a certain amount of time, before going
456→ * out to deliver letters. While the mail man is going out, more letters arrive
457→ * and can only be delivered once he is back. Once he is back the mail man will
458→ * do one more trip to deliver the letters that have accumulated while he was out.
459→ */
460→export class ThrottledDelayer<T> {
461→
462→	private delayer: Delayer<Promise<T>>;
463→	private throttler: Throttler;
464→
465→	constructor(defaultDelay: number) {
466→		this.delayer = new Delayer(defaultDelay);
467→		this.throttler = new Throttler();
468→	}
469→
470→	trigger(promiseFactory: ICancellableTask<Promise<T>>, delay?: number): Promise<T> {
471→		return this.delayer.trigger(() => this.throttler.queue(promiseFactory), delay) as unknown as Promise<T>;
472→	}
473→
474→	isTriggered(): boolean {
475→		return this.delayer.isTriggered();
476→	}
477→
478→	cancel(): void {
479→		this.delayer.cancel();
480→	}
481→
482→	dispose(): void {
483→		this.delayer.dispose();
484→		this.throttler.dispose();
485→	}
486→}
