489→ * A barrier that is initially closed and then becomes opened permanently.
490→ */
491→export class Barrier {
492→	private _isOpen: boolean;
493→	private _promise: Promise<boolean>;
494→	private _completePromise!: (v: boolean) => void;
495→
496→	constructor() {
497→		this._isOpen = false;
498→		this._promise = new Promise<boolean>((c, e) => {
499→			this._completePromise = c;
500→		});

 500→		});
