 536→export function timeout(millis: number): CancelablePromise<void>;
 537→export function timeout(millis: number, token: CancellationToken): Promise<void>;
 538→export function timeout(millis: number, token?: CancellationToken): CancelablePromise<void> | Promise<void> {
 539→	if (!token) {
 540→		return createCancelablePromise(token => timeout(millis, token));
 541→	}
 542→
 543→	return new Promise((resolve, reject) => {
 544→		const handle = setTimeout(() => {
 545→			disposable.dispose();
 546→			resolve();
 547→		}, millis);
 548→		const disposable = token.onCancellationRequested(() => {
 549→			clearTimeout(handle);
 550→			disposable.dispose();
 551→			reject(new CancellationError());
 552→		});
 553→	});
 554→}
