 556→/**
 557→ * Creates a timeout that can be disposed using its returned value.
 558→ * @param handler The timeout handler.
 559→ * @param timeout An optional timeout in milliseconds.
 560→ * @param store An optional {@link DisposableStore} that will have the timeout disposable managed automatically.
 561→ *
 562→ * @example
 563→ * const store = new DisposableStore;
 564→ * // Call the timeout after 1000ms at which point it will be automatically
 565→ * // evicted from the store.
 566→ * const timeoutDisposable = disposableTimeout(() => {}, 1000, store);
 567→ *
 568→ * if (foo) {
 569→ *   // Cancel the timeout and evict it from store.
 570→ *   timeoutDisposable.dispose();
 571→ * }
 572→ */
 573→export function disposableTimeout(handler: () => void, timeout = 0, store?: DisposableStore): IDisposable {
 574→	const timer = setTimeout(() => {
 575→		handler();
 576→		if (store) {
 577→			disposable.dispose();
 578→		}
 579→	}, timeout);
 580→	const disposable = toDisposable(() => {
 581→		clearTimeout(timer);
 582→		store?.delete(disposable);
 583→	});
 584→	store?.add(disposable);
 585→	return disposable;
 586→}
