 588→/**
 589→ * Runs the provided list of promise factories in sequential order. The returned
 590→ * promise will complete to an array of results from each promise.
 591→ */
 592→
 593→export function sequence<T>(promiseFactories: ITask<Promise<T>>[]): Promise<T[]> {
 594→	const results: T[] = [];
 595→	let index = 0;
 596→	const len = promiseFactories.length;
 597→
 598→	function next(): Promise<T> | null {
 599→		return index < len ? promiseFactories[index++]() : null;
 600→	}
 601→
 602→	function thenHandler(result: unknown): Promise<any> {
 603→		if (result !== undefined && result !== null) {
 604→			results.push(result as T);
 605→		}
 606→
 607→		const n = next();
 608→		if (n) {
 609→			return n.then(thenHandler);
 610→		}
 611→
 612→		return Promise.resolve(results);
 613→	}
 614→
 615→	return Promise.resolve(null).then(thenHandler);
 616→}
 617→
 618→export function first<T>(promiseFactories: ITask<Promise<T>>[], shouldStop: (t: T) => boolean = t => !!t, defaultValue: T | null = null): Promise<T | null> {
 619→	let index = 0;
 620→	const len = promiseFactories.length;
 621→
 622→	const loop: () => Promise<T | null> = () => {
 623→		if (index >= len) {
 624→			return Promise.resolve(defaultValue);
 625→		}
 626→
 627→		const factory = promiseFactories[index++];
 628→		const promise = Promise.resolve(factory());
 629→
 630→		return promise.then(result => {
 631→			if (shouldStop(result)) {
 632→				return Promise.resolve(result);
 633→			}
 634→
 635→			return loop();
 636→		});
 637→	};
 638→
 639→	return loop();
 640→}
 641→
 642→/**
 643→ * Returns the result of the first promise that matches the "shouldStop",
 644→ * running all promises in parallel. Supports cancelable promises.
 645→ */
 646→export function firstParallel<T>(promiseList: Promise<T>[], shouldStop?: (t: T) => boolean, defaultValue?: T | null): Promise<T | null>;
 647→export function firstParallel<T, R extends T>(promiseList: Promise<T>[], shouldStop: (t: T) => t is R, defaultValue?: R | null): Promise<R | null>;
 648→export function firstParallel<T>(promiseList: Promise<T>[], shouldStop: (t: T) => boolean = t => !!t, defaultValue: T | null = null) {
 649→	if (promiseList.length === 0) {
 650→		return Promise.resolve(defaultValue);
 651→	}
 652→
 653→	let todo = promiseList.length;
 654→	const finish = () => {
 655→		todo = -1;
 656→		for (const promise of promiseList) {
 657→			(promise as Partial<CancelablePromise<T>>).cancel?.();
 658→		}
 659→	};
 660→
 661→	return new Promise<T | null>((resolve, reject) => {
 662→		for (const promise of promiseList) {
 663→			promise.then(result => {
 664→				if (--todo >= 0 && shouldStop(result)) {
 665→					finish();
 666→					resolve(result);
 667→				} else if (todo === 0) {
 668→					resolve(defaultValue);
 669→				}
 670→			})
 671→				.catch(err => {
 672→					if (--todo >= 0) {
 673→						finish();
 674→						reject(err);
 675→					}
 676→				});
 677→		}
 678→	});
 679→}
