 681→interface ILimitedTaskFactory<T> {
 682→	factory: ITask<Promise<T>>;
 683→	c: (value: T | Promise<T>) => void;
 684→	e: (error?: unknown) => void;
 685→}
 686→
 687→export interface ILimiter<T> {
 688→
 689→	readonly size: number;
 690→
 691→	queue(factory: ITask<Promise<T>>): Promise<T>;
 692→
 693→	clear(): void;
 694→}
