 788→/**
 789→ * A queue is handles one promise at a time and guarantees that at any time only one promise is executing.
 790→ */
 791→export class Queue<T> extends Limiter<T> {
 792→
 793→	constructor() {
 794→		super(1);
 795→	}
 796→}
