 823→/**
 824→ * A helper to organize queues per resource. The ResourceQueue makes sure to manage queues per resource
 825→ * by disposing them once the queue is empty.
 826→ */
 827→export class ResourceQueue implements IDisposable {
 828→
 829→	private readonly queues = new Map<string, Queue<void>>();
 830→
 831→	private readonly drainers = new Set<DeferredPromise<void>>();
 832→
 833→	private drainListeners: DisposableMap<number> | undefined = undefined;
 834→	private drainListenerCount = 0;
 835→
 836→	async whenDrained(): Promise<void> {
 837→		if (this.isDrained()) {
 838→			return;
 839→		}
 840→
 841→		const promise = new DeferredPromise<void>();
 842→		this.drainers.add(promise);
 843→
 844→		return promise.p;
 845→	}
 846→
 847→	private isDrained(): boolean {
 848→		for (const [, queue] of this.queues) {
 849→			if (queue.size > 0) {
 850→				return false;
 851→			}
 852→		}
 853→
 854→		return true;
 855→	}
 856→
 857→	queueSize(resource: URI, extUri: IExtUri = defaultExtUri): number {
 858→		const key = extUri.getComparisonKey(resource);
 859→
 860→		return this.queues.get(key)?.size ?? 0;
 861→	}
 862→
 863→	queueFor(resource: URI, factory: ITask<Promise<void>>, extUri: IExtUri = defaultExtUri): Promise<void> {
 864→		const key = extUri.getComparisonKey(resource);
 865→
 866→		let queue = this.queues.get(key);
 867→		if (!queue) {
 868→			queue = new Queue<void>();
 869→			const drainListenerId = this.drainListenerCount++;
 870→			const drainListener = Event.once(queue.onDrained)(() => {
 871→				queue?.dispose();
 872→				this.queues.delete(key);
 873→				this.onDidQueueDrain();
 874→
 875→				this.drainListeners?.deleteAndDispose(drainListenerId);
 876→
 877→				if (this.drainListeners?.size === 0) {
 878→					this.drainListeners.dispose();
 879→					this.drainListeners = undefined;
 880→				}
 881→			});
 882→
 883→			if (!this.drainListeners) {
 884→				this.drainListeners = new DisposableMap();
 885→			}
 886→			this.drainListeners.set(drainListenerId, drainListener);
 887→
 888→			this.queues.set(key, queue);
 889→		}
 890→
 891→		return queue.queue(factory);
 892→	}
 893→
 894→	private onDidQueueDrain(): void {
 895→		if (!this.isDrained()) {
 896→			return; // not done yet
 897→		}
 898→
 899→		this.releaseDrainers();
 900→	}
 901→
 902→	private releaseDrainers(): void {
 903→		for (const drainer of this.drainers) {
 904→			drainer.complete();
 905→		}
 906→
 907→		this.drainers.clear();
 908→	}
 909→
 910→	dispose(): void {
 911→		for (const [, queue] of this.queues) {
 912→			queue.dispose();
 913→		}
 914→
 915→		this.queues.clear();
 916→
 917→		// Even though we might still have pending
 918→		// tasks queued, after the queues have been
 919→		// disposed, we can no longer track them, so
 920→		// we release drainers to prevent hanging
 921→		// promises when the resource queue is being
 922→		// disposed.
 923→		this.releaseDrainers();
 924→
 925→		this.drainListeners?.dispose();
 926→	}
 927→}
