1015→export class TimeoutTimer implements IDisposable {
1016→	private _token: Timeout | undefined;
1017→	private _isDisposed = false;
1018→
1019→	constructor();
1020→	constructor(runner: () => void, timeout: number);
1021→	constructor(runner?: () => void, timeout?: number) {
1022→		this._token = undefined;
1023→
1024→		if (typeof runner === 'function' && typeof timeout === 'number') {
1025→			this.setIfNotSet(runner, timeout);
1026→		}
1027→	}
1028→
1029→	dispose(): void {
1030→		this.cancel();
1031→		this._isDisposed = true;
1032→	}
1033→
1034→	cancel(): void {
1035→		if (this._token !== undefined) {
1036→			clearTimeout(this._token);
1037→			this._token = undefined;
1038→		}
1039→	}
1040→
1041→	cancelAndSet(runner: () => void, timeout: number): void {
1042→		if (this._isDisposed) {
1043→			throw new BugIndicatingError(`Calling 'cancelAndSet' on a disposed TimeoutTimer`);
1044→		}
1045→
1046→		this.cancel();
1047→		this._token = setTimeout(() => {
1048→			this._token = undefined;
1049→			runner();
1050→		}, timeout);
1051→	}
1052→
1053→	setIfNotSet(runner: () => void, timeout: number): void {
1054→		if (this._isDisposed) {
1055→			throw new BugIndicatingError(`Calling 'setIfNotSet' on a disposed TimeoutTimer`);
1056→		}
1057→
1058→		if (this._token !== undefined) {
1059→			// timer is already set
1060→			return;
1061→		}
1062→		this._token = setTimeout(() => {
1063→			this._token = undefined;
1064→			runner();
1065→		}, timeout);
1066→	}
1067→}
