1076→		this.disposable = undefined;
1077→	}
1078→
1079→	cancelAndSet(runner: () => void, interval: number, context = globalThis): void {
1080→		if (this.isDisposed) {
1081→			throw new BugIndicatingError(`Calling 'cancelAndSet' on a disposed IntervalTimer`);
1082→		}
