1101→export class RunOnceScheduler implements IDisposable {
1102→
1103→	protected runner: ((...args: unknown[]) => void) | null;
1104→
1105→	private timeoutToken: Timeout | undefined;
1106→	private timeout: number;
1107→	private timeoutHandler: () => void;
1108→
1109→	constructor(runner: (...args: any[]) => void, delay: number) {
1110→		this.timeoutToken = undefined;
1111→		this.runner = runner;
1112→		this.timeout = delay;
1113→		this.timeoutHandler = this.onTimeout.bind(this);
1114→	}
1115→
1116→	/**
1117→	 * Dispose RunOnceScheduler
1118→	 */
1119→	dispose(): void {
1120→		this.cancel();
1121→		this.runner = null;
1122→	}
1123→
1124→	/**
1125→	 * Cancel current scheduled runner (if any).
1126→	 */
1127→	cancel(): void {
1128→		if (this.isScheduled()) {
1129→			clearTimeout(this.timeoutToken);
1130→			this.timeoutToken = undefined;
1131→		}
1132→	}
1133→
1134→	/**
1135→	 * Cancel previous runner (if any) & schedule a new runner.
1136→	 */
1137→	schedule(delay = this.timeout): void {
1138→		this.cancel();
1139→		this.timeoutToken = setTimeout(this.timeoutHandler, delay);
1140→	}
1141→
1142→	get delay(): number {
1143→		return this.timeout;
1144→	}
1145→
1146→	set delay(value: number) {
1147→		this.timeout = value;
1148→	}
1149→
1150→	/**
1151→	 * Returns true if scheduled.
1152→	 */
1153→	isScheduled(): boolean {
1154→		return this.timeoutToken !== undefined;
1155→	}
1156→
1157→	flush(): void {
1158→		if (this.isScheduled()) {
1159→			this.cancel();
1160→			this.doRun();
1161→		}
1162→	}
1163→
1164→	private onTimeout() {
1165→		this.timeoutToken = undefined;
