1249→export class RunOnceWorker<T> extends RunOnceScheduler {
1250→
1251→	private units: T[] = [];
1252→
1253→	constructor(runner: (units: T[]) => void, timeout: number) {
1254→		super(runner, timeout);
1255→	}
1256→
1257→	work(unit: T): void {
1258→		this.units.push(unit);
1259→
1260→		if (!this.isScheduled()) {
1261→			this.schedule();
1262→		}
1263→	}
1264→
1265→	protected override doRun(): void {
1266→		const units = this.units;
1267→		this.units = [];
1268→
1269→		this.runner?.(units);
1270→	}
1271→
1272→	override dispose(): void {
