1279→export interface IThrottledWorkerOptions {
1280→
1281→	/**
1282→	 * maximum of units the worker will pass onto handler at once
1283→	 */
1284→	maxWorkChunkSize: number;
1285→
1286→	/**
1287→	 * maximum of units the worker will keep in memory for processing
1288→	 */
1289→	maxBufferedWork: number | undefined;
1290→
1291→	/**
1292→	 * delay before processing the next round of chunks when chunk size exceeds limits
1293→	 */
1294→	throttleDelay: number;
1295→
1296→	/**
1297→	 * When enabled will guarantee that two distinct calls to `work()` are not executed
1298→	 * without throttle delay between them.
1299→	 * Otherwise if the worker isn't currently throttling it will execute work immediately.
1300→	 */
1301→	waitThrottleDelayBetweenWorkUnits?: boolean;
1302→}
1303→
1304→/**
1305→ * The `ThrottledWorker` will accept units of work `T`
1306→ * to handle. The contract is:
1307→ * * there is a maximum of units the worker can handle at once (via `maxWorkChunkSize`)
1308→ * * there is a maximum of units the worker will keep in memory for processing (via `maxBufferedWork`)
1309→ * * after having handled `maxWorkChunkSize` units, the worker needs to rest (via `throttleDelay`)
1310→ */
1311→export class ThrottledWorker<T> extends Disposable {
1312→
1313→	private readonly pendingWork: T[] = [];
1314→
1315→	private readonly throttler = this._register(new MutableDisposable<RunOnceScheduler>());
1316→	private disposed = false;
1317→	private lastExecutionTime = 0;
1318→
1319→	constructor(
1320→		private options: IThrottledWorkerOptions,
1321→		private readonly handler: (units: T[]) => void
1322→	) {
1323→		super();
1324→	}
1325→
1326→	/**
1327→	 * The number of work units that are pending to be processed.
1328→	 */
1329→	get pending(): number { return this.pendingWork.length; }
1330→
1331→	/**
1332→	 * Add units to be worked on. Use `pending` to figure out
1333→	 * how many units are not yet processed after this method
1334→	 * was called.
1335→	 *
1336→	 * @returns whether the work was accepted or not. If the
1337→	 * worker is disposed, it will not accept any more work.
1338→	 * If the number of pending units would become larger
1339→	 * than `maxPendingWork`, more work will also not be accepted.
1340→	 */
1341→	work(units: readonly T[]): boolean {
1342→		if (this.disposed) {
1343→			return false; // work not accepted: disposed
1344→		}
1345→
1346→		// Check for reaching maximum of pending work
1347→		if (typeof this.options.maxBufferedWork === 'number') {
1348→
1349→			// Throttled: simple check if pending + units exceeds max pending
1350→			if (this.throttler.value) {
1351→				if (this.pending + units.length > this.options.maxBufferedWork) {
1352→					return false; // work not accepted: too much pending work
1353→				}
1354→			}
1355→
1356→			// Unthrottled: same as throttled, but account for max chunk getting
1357→			// worked on directly without being pending
1358→			else {
1359→				if (this.pending + units.length - this.options.maxWorkChunkSize > this.options.maxBufferedWork) {
1360→					return false; // work not accepted: too much pending work
1361→				}
1362→			}
1363→		}
1364→
1365→		// Add to pending units first
1366→		for (const unit of units) {
1367→			this.pendingWork.push(unit);
1368→		}
1369→
1370→		const timeSinceLastExecution = Date.now() - this.lastExecutionTime;
1371→
1372→		if (!this.throttler.value && (!this.options.waitThrottleDelayBetweenWorkUnits || timeSinceLastExecution >= this.options.throttleDelay)) {
1373→			// Work directly if we are not throttling and we are not
1374→			// enforced to throttle between `work()` calls.
1375→			this.doWork();
1376→		} else if (!this.throttler.value && this.options.waitThrottleDelayBetweenWorkUnits) {
1377→			// Otherwise, schedule the throttler to work.
1378→			this.scheduleThrottler(Math.max(this.options.throttleDelay - timeSinceLastExecution, 0));
1379→		} else {
1380→			// Otherwise, our work will be picked up by the running throttler
1381→		}
1382→
1383→		return true; // work accepted
1384→	}
1385→
1386→	private doWork(): void {
1387→		this.lastExecutionTime = Date.now();
1388→
1389→		// Extract chunk to handle and handle it
1390→		this.handler(this.pendingWork.splice(0, this.options.maxWorkChunkSize));
1391→
1392→		// If we have remaining work, schedule it after a delay
1393→		if (this.pendingWork.length > 0) {
1394→			this.scheduleThrottler();
1395→		}
1396→	}
1397→
1398→	private scheduleThrottler(delay = this.options.throttleDelay): void {
1399→		this.throttler.value = new RunOnceScheduler(() => {
1400→			this.throttler.clear();
1401→
1402→			this.doWork();
1403→		}, delay);
1404→		this.throttler.value.schedule();
1405→	}
1406→
1407→	override dispose(): void {
1408→		super.dispose();
1409→
1410→		this.pendingWork.length = 0;
1411→		this.disposed = true;
1412→	}
1413→}
