1415→//#region -- run on idle tricks ------------
1416→
1417→export interface IdleDeadline {
1418→	readonly didTimeout: boolean;
1419→	timeRemaining(): number;
1420→}
1421→
1422→type IdleApi = Pick<typeof globalThis, 'requestIdleCallback' | 'cancelIdleCallback'>;
1423→
1424→
1425→/**
1426→ * Execute the callback the next time the browser is idle, returning an
1427→ * {@link IDisposable} that will cancel the callback when disposed. This wraps
1428→ * [requestIdleCallback] so it will fallback to [setTimeout] if the environment
1429→ * doesn't support it.
1430→ *
1431→ * @param callback The callback to run when idle, this includes an
1432→ * [IdleDeadline] that provides the time alloted for the idle callback by the
1433→ * browser. Not respecting this deadline will result in a degraded user
1434→ * experience.
1435→ * @param timeout A timeout at which point to queue no longer wait for an idle
1436→ * callback but queue it on the regular event loop (like setTimeout). Typically
1437→ * this should not be used.
1438→ *
1439→ * [IdleDeadline]: https://developer.mozilla.org/en-US/docs/Web/API/IdleDeadline
1440→ * [requestIdleCallback]: https://developer.mozilla.org/en-US/docs/Web/API/Window/requestIdleCallback
1441→ * [setTimeout]: https://developer.mozilla.org/en-US/docs/Web/API/Window/setTimeout
1442→ *
1443→ * **Note** that there is `dom.ts#runWhenWindowIdle` which is better suited when running inside a browser
1444→ * context
1445→ */
1446→export let runWhenGlobalIdle: (callback: (idle: IdleDeadline) => void, timeout?: number) => IDisposable;
1447→
1448→export let _runWhenIdle: (targetWindow: IdleApi, callback: (idle: IdleDeadline) => void, timeout?: number) => IDisposable;
1449→
1450→(function () {
1451→	const safeGlobal: any = globalThis;
1452→	if (typeof safeGlobal.requestIdleCallback !== 'function' || typeof safeGlobal.cancelIdleCallback !== 'function') {
1453→		_runWhenIdle = (_targetWindow, runner, timeout?) => {
1454→			setTimeout0(() => {
1455→				if (disposed) {
1456→					return;
1457→				}
1458→				const end = Date.now() + 15; // one frame at 64fps
1459→				const deadline: IdleDeadline = {
1460→					didTimeout: true,
1461→					timeRemaining() {
1462→						return Math.max(0, end - Date.now());
1463→					}
1464→				};
1465→				runner(Object.freeze(deadline));
1466→			});
1467→			let disposed = false;
1468→			return {
1469→				dispose() {
1470→					if (disposed) {
1471→						return;
1472→					}
1473→					disposed = true;
1474→				}
1475→			};
1476→		};
1477→	} else {
1478→		_runWhenIdle = (targetWindow: typeof safeGlobal, runner, timeout?) => {
1479→			const handle: number = targetWindow.requestIdleCallback(runner, typeof timeout === 'number' ? { timeout } : undefined);
1480→			let disposed = false;
1481→			return {
1482→				dispose() {
1483→					if (disposed) {
1484→						return;
1485→					}
1486→					disposed = true;
1487→					targetWindow.cancelIdleCallback(handle);
1488→				}
1489→			};
1490→		};
1491→	}
1492→	runWhenGlobalIdle = (runner, timeout) => _runWhenIdle(globalThis, runner, timeout);
1493→})();
1494→
1495→export abstract class AbstractIdleValue<T> {
1496→
1497→	private readonly _executor: () => void;
1498→	private readonly _handle: IDisposable;
1499→
1500→	private _didRun: boolean = false;
1501→	private _value?: T;
1502→	private _error: unknown;
1503→
1504→	constructor(targetWindow: IdleApi, executor: () => T) {
1505→		this._executor = () => {
1506→			try {
1507→				this._value = executor();
1508→			} catch (err) {
1509→				this._error = err;
1510→			} finally {
1511→				this._didRun = true;
1512→			}
1513→		};
1514→		this._handle = _runWhenIdle(targetWindow, () => this._executor());
1515→	}
1516→
1517→	dispose(): void {
1518→		this._handle.dispose();
1519→	}
1520→
1521→	get value(): T {
1522→		if (!this._didRun) {
1523→			this._handle.dispose();
1524→			this._executor();
1525→		}
1526→		if (this._error) {
1527→			throw this._error;
1528→		}
1529→		return this._value!;
1530→	}
1531→
1532→	get isInitialized(): boolean {
1533→		return this._didRun;
1534→	}
1535→}
1536→
1537→/**
1538→ * An `IdleValue` that always uses the current window (which might be throttled or inactive)
1539→ *
1540→ * **Note** that there is `dom.ts#WindowIdleValue` which is better suited when running inside a browser
1541→ * context
1542→ */
1543→export class GlobalIdleValue<T> extends AbstractIdleValue<T> {
1544→
1545→	constructor(executor: () => T) {
1546→		super(globalThis, executor);
1547→	}
1548→}
