1551→
1552→export async function retry<T>(task: ITask<Promise<T>>, delay: number, retries: number): Promise<T> {
1553→	let lastError: Error | undefined;
1554→
1555→	for (let i = 0; i < retries; i++) {
1556→		try {
1557→			return await task();
1558→		} catch (error) {
1559→			lastError = error;
1560→
1561→			await timeout(delay);
1562→		}
1563→	}
1564→
1565→	throw lastError;
1566→}
