1721→export type ValueCallback<T = unknown> = (value: T | Promise<T>) => void;
1722→
1723→const enum DeferredOutcome {
1724→	Resolved,
1725→	Rejected
1726→}
1727→
1728→/**
1729→ * Creates a promise whose resolution or rejection can be controlled imperatively.
1730→ */
1731→export class DeferredPromise<T> {
1732→
1733→	public static fromPromise<T>(promise: Promise<T>): DeferredPromise<T> {
1734→		const deferred = new DeferredPromise<T>();
1735→		deferred.settleWith(promise);
1736→		return deferred;
1737→	}
1738→
1739→	private completeCallback!: ValueCallback<T>;
1740→	private errorCallback!: (err: unknown) => void;
1741→	private outcome?: { outcome: DeferredOutcome.Rejected; value: unknown } | { outcome: DeferredOutcome.Resolved; value: T };
1742→
1743→	public get isRejected() {
1744→		return this.outcome?.outcome === DeferredOutcome.Rejected;
1745→	}
1746→
1747→	public get isResolved() {
1748→		return this.outcome?.outcome === DeferredOutcome.Resolved;
1749→	}
1750→
1751→	public get isSettled() {
1752→		return !!this.outcome;
1753→	}
1754→
1755→	public get value() {
1756→		return this.outcome?.outcome === DeferredOutcome.Resolved ? this.outcome?.value : undefined;
1757→	}
1758→
1759→	public readonly p: Promise<T>;
1760→
1761→	constructor() {
1762→		this.p = new Promise<T>((c, e) => {
1763→			this.completeCallback = c;
1764→			this.errorCallback = e;
1765→		});
1766→	}
1767→
1768→	public complete(value: T) {
1769→		if (this.isSettled) {
1770→			return Promise.resolve();
1771→		}
1772→
1773→		return new Promise<void>(resolve => {
1774→			this.completeCallback(value);
1775→			this.outcome = { outcome: DeferredOutcome.Resolved, value };
1776→			resolve();
1777→		});
1778→	}
1779→
1780→	public error(err: unknown) {
1781→		if (this.isSettled) {
1782→			return Promise.resolve();
1783→		}
1784→
1785→		return new Promise<void>(resolve => {
1786→			this.errorCallback(err);
1787→			this.outcome = { outcome: DeferredOutcome.Rejected, value: err };
1788→			resolve();
1789→		});
1790→	}
1791→
1792→	public settleWith(promise: Promise<T>): Promise<void> {
1793→		return promise.then(
1794→			value => this.complete(value),
1795→			error => this.error(error)
1796→		);
1797→	}
1798→
1799→	public cancel() {
1800→		return this.error(new CancellationError());
1801→	}
1802→}
