374→			onWillAddFirstListener() {
375→				subscription = event(cur => {
376→					numThrottledCalls++;
377→					output = merge(output, cur);
378→
379→					// If not currently throttling, fire immediately if leading is enabled
380→					if (handle === undefined) {
381→						if (leading) {
382→							emitter.fire(output);
383→							output = undefined;
384→							numThrottledCalls = 0;
385→						}
386→
387→						// Set up the throttle period
388→						if (typeof delay === 'number') {
389→							handle = setTimeout(() => {
390→								// Fire on trailing edge if there were calls during throttle period
391→								if (trailing && numThrottledCalls > 0) {
