405→								}
406→								output = undefined;
407→								handle = undefined;
408→								numThrottledCalls = 0;
409→							});
410→						}
411→					}
412→					// If already throttling, just accumulate the value for trailing edge
413→				});
414→			},
415→			onDidRemoveLastListener() {
416→				subscription.dispose();
417→			}
418→		};
419→
420→		if (!disposable) {
421→			_addLeakageTraceLogic(options);
422→		}
423→
424→		const emitter = new Emitter<O>(options);
425→
426→		disposable?.add(emitter);
427→
428→		return emitter.event;
