577→	export function chain<T, R>(event: Event<T>, sythensize: ($: IChainableSythensis<T>) => IChainableSythensis<R>): Event<R> {
578→		const fn: Event<R> = (listener, thisArgs, disposables) => {
579→			const cs = sythensize(new ChainableSynthesis()) as ChainableSynthesis;
580→			return event(function (value) {
581→				const result = cs.evaluate(value);
582→				if (result !== HaltChainable) {
583→					listener.call(thisArgs, result);
