 648→	export interface IChainableSythensis<T> {
 649→		map<O>(fn: (i: T) => O): IChainableSythensis<O>;
 650→		forEach(fn: (i: T) => void): IChainableSythensis<T>;
 651→		filter<R extends T>(fn: (e: T) => e is R): IChainableSythensis<R>;
 652→		filter(fn: (e: T) => boolean): IChainableSythensis<T>;
 653→		reduce<R>(merge: (last: R, event: T) => R, initial: R): IChainableSythensis<R>;
 654→		reduce<R>(merge: (last: R | undefined, event: T) => R): IChainableSythensis<R>;
 655→		latch(equals?: (a: T, b: T) => boolean): IChainableSythensis<T>;
 656→	}
