 758→		constructor(readonly _observable: IObservable<T>, store: DisposableStore | undefined) {
 759→			const options: EmitterOptions = {
 760→				onWillAddFirstListener: () => {
 761→					_observable.addObserver(this);
 762→
 763→					// Communicate to the observable that we received its current value and would like to be notified about future changes.
 764→					this._observable.reportChanges();
 765→				},
 766→				onDidRemoveLastListener: () => {
 767→					_observable.removeObserver(this);
 768→				}
 769→			};
 770→			if (!store) {
 771→				_addLeakageTraceLogic(options);
 772→			}
 773→			this.emitter = new Emitter<T>(options);
 774→			if (store) {
 775→				store.add(this.emitter);
 776→			}
 777→		}
 778→
 779→		beginUpdate<T>(_observable: IObservable<T>): void {
 780→			// assert(_observable === this.obs);
 781→			this._counter++;
 782→		}
 783→
 784→		handlePossibleChange<T>(_observable: IObservable<T>): void {
 785→			// assert(_observable === this.obs);
 786→		}
 787→
 788→		handleChange<T, TChange>(_observable: IObservableWithChange<T, TChange>, _change: TChange): void {
 789→			// assert(_observable === this.obs);
 790→			this._hasChanged = true;
 791→		}
 792→
 793→		endUpdate<T>(_observable: IObservable<T>): void {
 794→			// assert(_observable === this.obs);
 795→			this._counter--;
 796→			if (this._counter === 0) {
 797→				this._observable.reportChanges();
 798→				if (this._hasChanged) {
 799→					this._hasChanged = false;
 800→					this.emitter.fire(this._observable.get());
 801→				}
 802→			}
 803→		}
 804→	}
