 820→			let count = 0;
 821→			let didChange = false;
 822→			const observer: IObserver = {
 823→				beginUpdate() {
 824→					count++;
 825→				},
 826→				endUpdate() {
 827→					count--;
 828→					if (count === 0) {
 829→						observable.reportChanges();
 830→						if (didChange) {
 831→							didChange = false;
 832→							listener.call(thisArgs);
 833→						}
 834→					}
 835→				},
 836→				handlePossibleChange() {
 837→					// noop
 838→				},
 839→				handleChange() {
 840→					didChange = true;
