 902→export class EventProfiling {
 903→
 904→	static readonly all = new Set<EventProfiling>();
 905→
 906→	private static _idPool = 0;
 907→
 908→	readonly name: string;
 909→	public listenerCount: number = 0;
 910→	public invocationCount = 0;
 911→	public elapsedOverall = 0;
 912→	public durations: number[] = [];
 913→
 914→	private _stopWatch?: StopWatch;
 915→
 916→	constructor(name: string) {
 917→		this.name = `${name}_${EventProfiling._idPool++}`;
 918→		EventProfiling.all.add(this);
 919→	}
 920→
 921→	start(listenerCount: number): void {
 922→		this._stopWatch = new StopWatch();
 923→		this.listenerCount = listenerCount;
 924→	}
