 926→	stop(): void {
 927→		if (this._stopWatch) {
 928→			const elapsed = this._stopWatch.elapsed();
 929→			this.durations.push(elapsed);
 930→			this.elapsedOverall += elapsed;
 931→			this.invocationCount += 1;
 932→			this._stopWatch = undefined;
 933→		}
 934→	}
 935→}
