 948→class LeakageMonitor {
 949→
 950→	private static _idPool = 1;
 951→
 952→	private _stacks: Map<string, number> | undefined;
 953→	private _warnCountdown: number = 0;
 954→
 955→	constructor(
 956→		private readonly _errorHandler: (err: Error) => void,
 957→		readonly threshold: number,
 958→		readonly name: string = (LeakageMonitor._idPool++).toString(16).padStart(3, '0')
 959→	) { }
 960→
 961→	dispose(): void {
 962→		this._stacks?.clear();
 963→	}
 964→
 965→	check(stack: Stacktrace, listenerCount: number): undefined | (() => void) {
 966→
 967→		const threshold = this.threshold;
 968→		if (threshold <= 0 || listenerCount < threshold) {
 969→			return undefined;
 970→		}
 971→
 972→		if (!this._stacks) {
 973→			this._stacks = new Map();
 974→		}
 975→		const count = (this._stacks.get(stack.value) || 0);
 976→		this._stacks.set(stack.value, count + 1);
 977→		this._warnCountdown -= 1;
 978→
 979→		if (this._warnCountdown <= 0) {
 980→			// only warn on first exceed and then every time the limit
 981→			// is exceeded by 50% again
 982→			this._warnCountdown = threshold * 0.5;
 983→
 984→			const [topStack, topCount] = this.getMostFrequentStack()!;
 985→			const message = `[${this.name}] potential listener LEAK detected, having ${listenerCount} listeners already. MOST frequent listener (${topCount}):`;
 986→			console.warn(message);
 987→			console.warn(topStack);
 988→
 989→			const error = new ListenerLeakError(message, topStack);
 990→			this._errorHandler(error);
 991→		}
 992→
 993→		return () => {
 994→			const count = (this._stacks!.get(stack.value) || 0);
 995→			this._stacks!.set(stack.value, count - 1);
 996→		};
 997→	}
 998→
 999→	getMostFrequentStack(): [string, number] | undefined {
1000→		if (!this._stacks) {
1001→			return undefined;
1002→		}
1003→		let topStack: [string, number] | undefined;
1004→		let topCount: number = 0;
1005→		for (const [stack, count] of this._stacks) {
1006→			if (!topStack || topCount < count) {
1007→				topStack = [stack, count];
1008→				topCount = count;
1009→			}
1010→		}
1011→		return topStack;
1012→	}
1013→}
