1048→let id = 0;
1049→class UniqueContainer<T> {
1050→	stack?: Stacktrace;
1051→	public id = id++;
1052→	constructor(public readonly value: T) { }
1053→}
1054→const compactionThreshold = 2;
1055→
1056→type ListenerContainer<T> = UniqueContainer<(data: T) => void>;
1057→type ListenerOrListeners<T> = (ListenerContainer<T> | undefined)[] | ListenerContainer<T>;
1058→
1059→const forEachListener = <T>(listeners: ListenerOrListeners<T>, fn: (c: ListenerContainer<T>) => void) => {
1060→	if (listeners instanceof UniqueContainer) {
1061→		fn(listeners);
1062→	} else {
1063→		for (let i = 0; i < listeners.length; i++) {
1064→			const l = listeners[i];
1065→			if (l) {
1066→				fn(l);
1067→			}
1068→		}
1069→	}
1070→};
