1072→/**
1073→ * The Emitter can be used to expose an Event to the public
1074→ * to fire it from the insides.
1075→ * Sample:
1076→	class Document {
1077→
1078→		private readonly _onDidChange = new Emitter<(value:string)=>any>();
1079→
1080→		public onDidChange = this._onDidChange.event;
1081→
1082→		// getter-style
1083→		// get onDidChange(): Event<(value:string)=>any> {
1084→		// 	return this._onDidChange.event;
1085→		// }
1086→
1087→		private _doIt() {
1088→			//...
1089→			this._onDidChange.fire(value);
1090→		}
1091→	}
1092→ */
1093→export class Emitter<T> {
1094→
1095→	private readonly _options?: EmitterOptions;
1096→	private readonly _leakageMon?: LeakageMonitor;
1097→	private readonly _perfMon?: EventProfiling;
1098→	private _disposed?: true;
1099→	private _event?: Event<T>;
1100→
1101→	/**
1102→	 * A listener, or list of listeners. A single listener is the most common
1103→	 * for event emitters (#185789), so we optimize that special case to avoid
1104→	 * wrapping it in an array (just like Node.js itself.)
1105→	 *
1106→	 * A list of listeners never 'downgrades' back to a plain function if
1107→	 * listeners are removed, for two reasons:
1108→	 *
1109→	 *  1. That's complicated (especially with the deliveryQueue)
1110→	 *  2. A listener with >1 listener is likely to have >1 listener again at
1111→	 *     some point, and swapping between arrays and functions may[citation needed]
1112→	 *     introduce unnecessary work and garbage.
1113→	 *
1114→	 * The array listeners can be 'sparse', to avoid reallocating the array
1115→	 * whenever any listener is added or removed. If more than `1 / compactionThreshold`
1116→	 * of the array is empty, only then is it resized.
1117→	 */
1118→	protected _listeners?: ListenerOrListeners<T>;
1119→
1120→	/**
1121→	 * Always to be defined if _listeners is an array. It's no longer a true
1122→	 * queue, but holds the dispatching 'state'. If `fire()` is called on an
1123→	 * emitter, any work left in the _deliveryQueue is finished first.
1124→	 */
1125→	private _deliveryQueue?: EventDeliveryQueuePrivate;
1126→	protected _size = 0;
1127→
1128→	constructor(options?: EmitterOptions) {
1129→		this._options = options;
1130→		this._leakageMon = (_globalLeakWarningThreshold > 0 || this._options?.leakWarningThreshold)
1131→			? new LeakageMonitor(options?.onListenerError ?? onUnexpectedError, this._options?.leakWarningThreshold ?? _globalLeakWarningThreshold) :
1132→			undefined;
1133→		this._perfMon = this._options?._profName ? new EventProfiling(this._options._profName) : undefined;
1134→		this._deliveryQueue = this._options?.deliveryQueue as EventDeliveryQueuePrivate | undefined;
1135→	}
1136→
1137→	dispose() {
1138→		if (!this._disposed) {
1139→			this._disposed = true;
1140→
1141→			// It is bad to have listeners at the time of disposing an emitter, it is worst to have listeners keep the emitter
1142→			// alive via the reference that's embedded in their disposables. Therefore we loop over all remaining listeners and
1143→			// unset their subscriptions/disposables. Looping and blaming remaining listeners is done on next tick because the
1144→			// the following programming pattern is very popular:
1145→			//
1146→			// const someModel = this._disposables.add(new ModelObject()); // (1) create and register model
1147→			// this._disposables.add(someModel.onDidChange(() => { ... }); // (2) subscribe and register model-event listener
1148→			// ...later...
1149→			// this._disposables.dispose(); disposes (1) then (2): don't warn after (1) but after the "overall dispose" is done
1150→
1151→			if (this._deliveryQueue?.current === this) {
1152→				this._deliveryQueue.reset();
1153→			}
1154→			if (this._listeners) {
1155→				if (_enableDisposeWithListenerWarning) {
1156→					const listeners = this._listeners;
1157→					queueMicrotask(() => {
1158→						forEachListener(listeners, l => l.stack?.print());
1159→					});
1160→				}
1161→
1162→				this._listeners = undefined;
1163→				this._size = 0;
1164→			}
1165→			this._options?.onDidRemoveLastListener?.();
1166→			this._leakageMon?.dispose();
1167→		}
1168→	}
1169→
1170→	/**
1171→	 * For the public to allow to subscribe
1172→	 * to events from this Emitter
1173→	 */
1174→	get event(): Event<T> {
1175→		this._event ??= (callback: (e: T) => unknown, thisArgs?: any, disposables?: IDisposable[] | DisposableStore) => {
1176→			if (this._leakageMon && this._size > this._leakageMon.threshold ** 2) {
1177→				const message = `[${this._leakageMon.name}] REFUSES to accept new listeners because it exceeded its threshold by far (${this._size} vs ${this._leakageMon.threshold})`;
1178→				console.warn(message);
1179→
1180→				const tuple = this._leakageMon.getMostFrequentStack() ?? ['UNKNOWN stack', -1];
1181→				const error = new ListenerRefusalError(`${message}. HINT: Stack shows most frequent listener (${tuple[1]}-times)`, tuple[0]);
1182→				const errorHandler = this._options?.onListenerError || onUnexpectedError;
1183→				errorHandler(error);
1184→
1185→				return Disposable.None;
1186→			}
1187→
1188→			if (this._disposed) {
1189→				// todo: should we warn if a listener is added to a disposed emitter? This happens often
1190→				return Disposable.None;
1191→			}
1192→
1193→			if (thisArgs) {
1194→				callback = callback.bind(thisArgs);
1195→			}
1196→
1197→			const contained = new UniqueContainer(callback);
1198→
1199→			let removeMonitor: Function | undefined;
1200→			let stack: Stacktrace | undefined;
1201→			if (this._leakageMon && this._size >= Math.ceil(this._leakageMon.threshold * 0.2)) {
1202→				// check and record this emitter for potential leakage
1203→				contained.stack = Stacktrace.create();
1204→				removeMonitor = this._leakageMon.check(contained.stack, this._size + 1);
1205→			}
1206→
1207→			if (_enableDisposeWithListenerWarning) {
1208→				contained.stack = stack ?? Stacktrace.create();
1209→			}
1210→
1211→			if (!this._listeners) {
1212→				this._options?.onWillAddFirstListener?.(this);
1213→				this._listeners = contained;
1214→				this._options?.onDidAddFirstListener?.(this);
1215→			} else if (this._listeners instanceof UniqueContainer) {
1216→				this._deliveryQueue ??= new EventDeliveryQueuePrivate();
1217→				this._listeners = [this._listeners, contained];
1218→			} else {
1219→				this._listeners.push(contained);
1220→			}
1221→			this._options?.onDidAddListener?.(this);
1222→
1223→			this._size++;
1224→
1225→
1226→			const result = toDisposable(() => {
1227→				removeMonitor?.();
1228→				this._removeListener(contained);
1229→			});
1230→			addToDisposables(result, disposables);
1231→
1232→			return result;
1233→		};
1234→
1235→		return this._event;
1236→	}
1237→
1238→	private _removeListener(listener: ListenerContainer<T>) {
1239→		this._options?.onWillRemoveListener?.(this);
1240→
1241→		if (!this._listeners) {
1242→			return; // expected if a listener gets disposed
1243→		}
1244→
1245→		if (this._size === 1) {
1246→			this._listeners = undefined;
1247→			this._options?.onDidRemoveLastListener?.(this);
1248→			this._size = 0;
1249→			return;
1250→		}
1251→
1252→		// size > 1 which requires that listeners be a list:
1253→		const listeners = this._listeners as (ListenerContainer<T> | undefined)[];
1254→
1255→		const index = listeners.indexOf(listener);
1256→		if (index === -1) {
1257→			console.log('disposed?', this._disposed);
1258→			console.log('size?', this._size);
1259→			console.log('arr?', JSON.stringify(this._listeners));
1260→			throw new Error('Attempted to dispose unknown listener');
1261→		}
1262→
1263→		this._size--;
1264→		listeners[index] = undefined;
1265→
1266→		const adjustDeliveryQueue = this._deliveryQueue!.current === this;
1267→		if (this._size * compactionThreshold <= listeners.length) {
1268→			let n = 0;
1269→			for (let i = 0; i < listeners.length; i++) {
1270→				if (listeners[i]) {
1271→					listeners[n++] = listeners[i];
1272→				} else if (adjustDeliveryQueue && n < this._deliveryQueue!.end) {
1273→					this._deliveryQueue!.end--;
1274→					if (n < this._deliveryQueue!.i) {
1275→						this._deliveryQueue!.i--;
1276→					}
1277→				}
1278→			}
1279→			listeners.length = n;
1280→		}
1281→	}
1282→
1283→	private _deliver(listener: undefined | UniqueContainer<(value: T) => void>, value: T) {
1284→		if (!listener) {
1285→			return;
1286→		}
1287→
1288→		const errorHandler = this._options?.onListenerError || onUnexpectedError;
1289→		if (!errorHandler) {
1290→			listener.value(value);
1291→			return;
1292→		}
1293→
1294→		try {
1295→			listener.value(value);
1296→		} catch (e) {
1297→			errorHandler(e);
1298→		}
1299→	}

1300→
1301→	/** Delivers items in the queue. Assumes the queue is ready to go. */
1302→	private _deliverQueue(dq: EventDeliveryQueuePrivate) {
1303→		const listeners = dq.current!._listeners! as (ListenerContainer<T> | undefined)[];
1304→		while (dq.i < dq.end) {
1305→			// important: dq.i is incremented before calling deliver() because it might reenter deliverQueue()
1306→			this._deliver(listeners[dq.i++], dq.value as T);
1307→		}
1308→		dq.reset();
1309→	}
1310→
1311→	/**
1312→	 * To be kept private to fire an event to
1313→	 * subscribers
1314→	 */
1315→	fire(event: T): void {
1316→		if (this._deliveryQueue?.current) {
1317→			this._deliverQueue(this._deliveryQueue);
1318→			this._perfMon?.stop(); // last fire() will have starting perfmon, stop it before starting the next dispatch
1319→		}
1320→
1321→		this._perfMon?.start(this._size);
1322→
1323→		if (!this._listeners) {
1324→			// no-op
1325→		} else if (this._listeners instanceof UniqueContainer) {
1326→			this._deliver(this._listeners, event);
1327→		} else {
1328→			const dq = this._deliveryQueue!;
1329→			dq.enqueue(this, event, this._listeners.length);
1330→			this._deliverQueue(dq);
1331→		}
1332→
1333→		this._perfMon?.stop();
1334→	}
1335→
1336→	hasListeners(): boolean {
1337→		return this._size > 0;
1338→	}
1339→}
