1347→class EventDeliveryQueuePrivate implements EventDeliveryQueue {
1348→	declare _isEventDeliveryQueue: true;
1349→
1350→	/**
1351→	 * Index in current's listener list.
1352→	 */
1353→	public i = -1;
1354→
1355→	/**
1356→	 * The last index in the listener's list to deliver.
1357→	 */
1358→	public end = 0;
1359→
1360→	/**
1361→	 * Emitter currently being dispatched on. Emitter._listeners is always an array.
1362→	 */
