1383→export interface IWaitUntil {
1384→	token: CancellationToken;
1385→	waitUntil(thenable: Promise<unknown>): void;
1386→}
1387→
1388→export type IWaitUntilData<T> = Omit<Omit<T, 'waitUntil'>, 'token'>;
1389→
1390→export class AsyncEmitter<T extends IWaitUntil> extends Emitter<T> {
1391→
1392→	private _asyncDeliveryQueue?: LinkedList<[(ev: T) => void, IWaitUntilData<T>]>;
1393→
1394→	async fireAsync(data: IWaitUntilData<T>, token: CancellationToken, promiseJoin?: (p: Promise<unknown>, listener: Function) => Promise<unknown>): Promise<void> {
1395→		if (!this._listeners) {
1396→			return;
1397→		}
1398→
1399→		if (!this._asyncDeliveryQueue) {
1400→			this._asyncDeliveryQueue = new LinkedList();
1401→		}
1402→
1403→		forEachListener(this._listeners, listener => this._asyncDeliveryQueue!.push([listener.value, data]));
1404→
1405→		while (this._asyncDeliveryQueue.size > 0 && !token.isCancellationRequested) {
1406→
1407→			const [listener, data] = this._asyncDeliveryQueue.shift()!;
1408→			const thenables: Promise<unknown>[] = [];
1409→
1410→			// eslint-disable-next-line local/code-no-dangerous-type-assertions
1411→			const event = <T>{
1412→				...data,
1413→				token,
1414→				waitUntil: (p: Promise<unknown>): void => {
1415→					if (Object.isFrozen(thenables)) {
1416→						throw new Error('waitUntil can NOT be called asynchronous');
1417→					}
1418→					if (promiseJoin) {
1419→						p = promiseJoin(p, listener);
1420→					}
1421→					thenables.push(p);
1422→				}
1423→			};
1424→
1425→			try {
1426→				listener(event);
1427→			} catch (e) {
1428→				onUnexpectedError(e);
1429→				continue;
1430→			}
1431→
1432→			// freeze thenables-collection to enforce sync-calls to
1433→			// wait until and then wait for all thenables to resolve
1434→			Object.freeze(thenables);
1435→
1436→			await Promise.allSettled(thenables).then(values => {
1437→				for (const value of values) {
1438→					if (value.status === 'rejected') {
1439→						onUnexpectedError(value.reason);
1440→					}
1441→				}
1442→			});
1443→		}
1444→	}
1445→}
