1448→export class PauseableEmitter<T> extends Emitter<T> {
1449→
1450→	private _isPaused = 0;
1451→	protected _eventQueue = new LinkedList<T>();
1452→	private _mergeFn?: (input: T[]) => T;
1453→
1454→	public get isPaused(): boolean {
1455→		return this._isPaused !== 0;
1456→	}
1457→
1458→	constructor(options?: EmitterOptions & { merge?: (input: T[]) => T }) {
1459→		super(options);
1460→		this._mergeFn = options?.merge;
1461→	}
1462→
1463→	pause(): void {
1464→		this._isPaused++;
1465→	}
1466→
1467→	resume(): void {
1468→		if (this._isPaused !== 0 && --this._isPaused === 0) {
1469→			if (this._mergeFn) {
1470→				// use the merge function to create a single composite
1471→				// event. make a copy in case firing pauses this emitter
1472→				if (this._eventQueue.size > 0) {
1473→					const events = Array.from(this._eventQueue);
1474→					this._eventQueue.clear();
1475→					super.fire(this._mergeFn(events));
1476→				}
1477→
1478→			} else {
1479→				// no merging, fire each event individually and test
1480→				// that this emitter isn't paused halfway through
