#### DisposableStore - Collection Management
```typescript
export class DisposableStore implements IDisposable {
    static DISABLE_DISPOSED_WARNING = false;

    private readonly _toDispose = new Set<IDisposable>();
    private _isDisposed = false;

    public dispose(): void {
        if (this._isDisposed) return;

        markAsDisposed(this);
        this._isDisposed = true;
        this.clear();
    }

    public get isDisposed(): boolean {
        return this._isDisposed;
    }

    public clear(): void {
        if (this._toDispose.size === 0) return;

        try {
            dispose(this._toDispose);
        } finally {
            this._toDispose.clear();
        }
    }

    public add<T extends IDisposable>(o: T): T {
        if (!o || o === Disposable.None) return o;
        if ((o as unknown as DisposableStore) === this) {
            throw new Error('Cannot register a disposable on itself!');
        }

        setParentOfDisposable(o, this);
        if (this._isDisposed) {
            console.warn(new Error('Trying to add to disposed store').stack);
        } else {
            this._toDispose.add(o);
        }
        return o;
    }

    public delete<T extends IDisposable>(o: T): void {
        if (!o) return;
        this._toDispose.delete(o);
        o.dispose();
    }

    public deleteAndLeak<T extends IDisposable>(o: T): void {
        if (!o) return;
        if (this._toDispose.delete(o)) {
            setParentOfDisposable(o, null);
        }
    }
}
