#### Emitter - Event Source
```typescript
export class Emitter<T> {
    private readonly _options?: EmitterOptions;
    private readonly _leakageMon?: LeakageMonitor;
    private _disposed?: true;
    private _event?: Event<T>;
    protected _listeners?: ListenerOrListeners<T>;
    private _deliveryQueue?: EventDeliveryQueuePrivate;
    protected _size = 0;

    constructor(options?: EmitterOptions) {
        this._options = options;
        this._leakageMon = (_globalLeakWarningThreshold > 0 || this._options?.leakWarningThreshold)
            ? new LeakageMonitor(options?.onListenerError ?? onUnexpectedError, ...)
            : undefined;
    }

    dispose() {
        if (!this._disposed) {
            this._disposed = true;

            if (this._deliveryQueue?.current === this) {
                this._deliveryQueue.reset();
            }

            if (this._listeners) {
                this._listeners = undefined;
                this._size = 0;
            }

            this._options?.onDidRemoveLastListener?.();
            this._leakageMon?.dispose();
        }
    }

    get event(): Event<T> {
        this._event ??= (callback: (e: T) => unknown, thisArgs?: any, disposables?: IDisposable[] | DisposableStore) => {
            if (this._disposed) return Disposable.None;

            if (thisArgs) {
                callback = callback.bind(thisArgs);
            }

            const contained = new UniqueContainer(callback);

            let removeMonitor: Function | undefined;
            if (this._leakageMon && this._size >= Math.ceil(this._leakageMon.threshold * 0.2)) {
                contained.stack = Stacktrace.create();
                removeMonitor = this._leakageMon.check(contained.stack, this._size + 1);
            }

            if (!this._listeners) {
                this._options?.onWillAddFirstListener?.(this);
                this._listeners = contained;
                this._options?.onDidAddFirstListener?.(this);
            } else if (this._listeners instanceof UniqueContainer) {
                this._deliveryQueue ??= new EventDeliveryQueuePrivate();
                this._listeners = [this._listeners, contained];
            } else {
                this._listeners.push(contained);
            }

            this._options?.onDidAddListener?.(this);
            this._size++;

            const result = toDisposable(() => {
                removeMonitor?.();
                this._removeListener(contained);
            });

            addToDisposables(result, disposables);
            return result;
        };
        return this._event;
    }

    fire(event: T): void {
        if (this._deliveryQueue?.current) {
            this._deliverQueue(this._deliveryQueue);
            this._perfMon?.stop();
        }

        this._perfMon?.start(this._size);

        if (!this._listeners) {
            // no-op
        } else if (this._listeners instanceof UniqueContainer) {
            this._deliver(this._listeners, event);
        } else {
            const dq = this._deliveryQueue!;
            dq.enqueue(this, event, this._listeners.length);
            this._deliverQueue(dq);
        }

        this._perfMon?.stop();
    }

    hasListeners(): boolean {
        return this._size > 0;
    }
}
