export class DebounceEmitter<T> extends PauseableEmitter<T> {
    private readonly _delay: number;
    private _handle: Timeout | undefined;

    override fire(event: T): void {
        if (!this._handle) {
            this.pause();
            this._handle = setTimeout(() => {
