#### Key Implementation: `createCancelablePromise<T>()`
```typescript
export function createCancelablePromise<T>(callback: (token: CancellationToken) => Promise<T>): CancelablePromise<T> {
    const source = new CancellationTokenSource();
    const thenable = callback(source.token);
    let isCancelled = false;

    const promise = new Promise<T>((resolve, reject) => {
        const subscription = source.token.onCancellationRequested(() => {
            isCancelled = true;
            subscription.dispose();
            reject(new CancellationError());
        });

        Promise.resolve(thenable).then(value => {
            subscription.dispose();
            source.dispose();

            if (!isCancelled) {
                resolve(value);
            } else if (isDisposable(value)) {
                // Automatic cleanup of disposable results on cancellation
                value.dispose();
            }
        }, err => {
            subscription.dispose();
            source.dispose();
            reject(err);
        });
    });

    return <CancelablePromise<T>>new class {
        cancel() {
            source.cancel();
            source.dispose();
        }
        // Implements then, catch, finally to act as Promise
    };
}
```

#### Key Features:
- Wraps promises with explicit cancellation support
- **Disposable integration**: If the resolved value implements `IDisposable`, it auto-disposes on cancellation
- Subscription cleanup via `subscription.dispose()` and `source.dispose()`
- Rejects with `CancellationError` when cancelled
- Returns a wrapper object implementing `CancelablePromise<T>` protocol

