#### Token Source: `CancellationTokenSource`
```typescript
export class CancellationTokenSource {
    private _token?: CancellationToken = undefined;
    private _parentListener?: IDisposable = undefined;

    constructor(parent?: CancellationToken) {
        // Parent propagation: if parent cancels, this source also cancels
        this._parentListener = parent && parent.onCancellationRequested(this.cancel, this);
    }

    get token(): CancellationToken {
        if (!this._token) {
            this._token = new MutableToken();
        }
        return this._token;
    }

    cancel(): void {
        if (!this._token) {
            this._token = CancellationToken.Cancelled;  // Optimize by reusing singleton
        } else if (this._token instanceof MutableToken) {
            this._token.cancel();
        }
    }

    dispose(cancel: boolean = false): void {
        if (cancel) {
            this.cancel();
        }
        this._parentListener?.dispose();
        if (this._token instanceof MutableToken) {
            this._token.dispose();
        }
    }
}
