#### Token Pooling: `CancellationTokenPool`
```typescript
export class CancellationTokenPool {
    private readonly _source = new CancellationTokenSource();
    private readonly _listeners = new DisposableStore();
    private _total: number = 0;
    private _cancelled: number = 0;
    private _isDone: boolean = false;

    // Pool cancels only when ALL tokens in pool are cancelled
    add(token: CancellationToken): void {
        if (this._isDone) return;

        this._total++;
        if (token.isCancellationRequested) {
            this._cancelled++;
            this._check();
            return;
        }

        const d = token.onCancellationRequested(() => {
            d.dispose();
            this._cancelled++;
            this._check();
        });
        this._listeners.add(d);
    }

    private _check(): void {
        if (!this._isDone && this._total > 0 && this._total === this._cancelled) {
            this._isDone = true;
            this._listeners.dispose();
            this._source.cancel();
        }
    }
}
```

#### Key Token Utilities:
- **`cancelOnDispose(store: DisposableStore): CancellationToken`** - Creates token that cancels when store is disposed
- **Parent-child propagation**: Source with parent cancels when parent cancels
- **Lazy Emitter**: Token only creates Emitter when listeners added (optimization)

