#### A. THROTTLER - Prevent Accumulation
```typescript
export class Throttler implements IDisposable {
    private activePromise: Promise<any> | null;
    private queuedPromise: Promise<any> | null;
    private queuedPromiseFactory: ICancellableTask<Promise<any>> | null;
    private cancellationTokenSource: CancellationTokenSource;

    queue<T>(promiseFactory: ICancellableTask<Promise<T>>): Promise<T> {
        if (this.cancellationTokenSource.token.isCancellationRequested) {
            return Promise.reject(new Error('Throttler is disposed'));
        }

        if (this.activePromise) {
            this.queuedPromiseFactory = promiseFactory;
            if (!this.queuedPromise) {
                const onComplete = () => {
                    this.queuedPromise = null;
                    if (!this.cancellationTokenSource.token.isCancellationRequested) {
                        return this.queue(this.queuedPromiseFactory!);
                    }
                };
                this.queuedPromise = new Promise(resolve => {
                    this.activePromise!.then(onComplete, onComplete).then(resolve);
                });
            }
            return this.queuedPromise;
        }

        // Pass cancellation token to factory
        this.activePromise = promiseFactory(this.cancellationTokenSource.token);
        return new Promise((resolve, reject) => {
            this.activePromise!.then((result: T) => {
                this.activePromise = null;
                resolve(result);
            }, (err: unknown) => {
                this.activePromise = null;
                reject(err);
            });
        });
    }

    dispose(): void {
        this.cancellationTokenSource.cancel();
    }
}
```

#### B. DELAYER - Debounce with Cancellation
```typescript
export class Delayer<T> implements IDisposable {
    private deferred: IScheduledLater | null;
    private completionPromise: Promise<any> | null;
    private task: ITask<T | Promise<T>> | null;

    trigger(task: ITask<T | Promise<T>>, delay = this.defaultDelay): Promise<T> {
        this.task = task;
        this.cancelTimeout();

        if (!this.completionPromise) {
            this.completionPromise = new Promise((resolve, reject) => {
                this.doResolve = resolve;
                this.doReject = reject;
            }).then(() => {
                this.completionPromise = null;
                if (this.task) {
                    const task = this.task;
                    this.task = null;
                    return task();
                }
            });
        }

        const fn = () => {
            this.deferred = null;
            this.doResolve?.(null);
        };

        // Supports MicrotaskDelay for microtask scheduling
        this.deferred = delay === MicrotaskDelay ? 
            microtaskDeferred(fn) : 
            timeoutDeferred(delay, fn);

        return this.completionPromise;
    }

    cancel(): void {
        this.cancelTimeout();
        if (this.completionPromise) {
            this.doReject?.(new CancellationError());
            this.completionPromise = null;
        }
    }

    dispose(): void {
        this.cancel();
    }
}
```

#### C. RETRY - Automatic Retrying
```typescript
export async function retry<T>(
    task: ITask<Promise<T>>, 
    delay: number, 
    retries: number
): Promise<T> {
    let lastError: Error | undefined;

    for (let i = 0; i < retries; i++) {
        try {
            return await task();
        } catch (error) {
            lastError = error;
            await timeout(delay);  // Uses cancellation-aware timeout
        }
    }

    throw lastError;
}
```

#### D. LIMITER - Parallel Execution Control
```typescript
export class Limiter<T> implements ILimiter<T> {
    private _size = 0;
    private _isDisposed = false;
    private runningPromises: number;
    private readonly maxDegreeOfParalellism: number;
    private readonly outstandingPromises: ILimitedTaskFactory<T>[];
    private readonly _onDrained: Emitter<void>;

    queue(factory: ITask<Promise<T>>): Promise<T> {
        if (this._isDisposed) {
            throw new Error('Object has been disposed');
        }
        this._size++;

        return new Promise<T>((c, e) => {
            this.outstandingPromises.push({ factory, c, e });
            this.consume();
        });
    }

    private consume(): void {
        while (this.outstandingPromises.length && 
               this.runningPromises < this.maxDegreeOfParalellism) {
            const task = this.outstandingPromises.shift()!;
            this.runningPromises++;

            const promise = task.factory();
            promise.then(task.c, task.e);
            promise.then(() => this.consumed(), () => this.consumed());
        }
    }

    get onDrained(): Event<void> {
        return this._onDrained.event;
    }

    dispose(): void {
        this._isDisposed = true;
        this.outstandingPromises.length = 0;
        this._size = 0;
        this._onDrained.dispose();
    }
}
```

#### E. THROTTLED DELAYER - Combined Pattern
```typescript
export class ThrottledDelayer<T> {
    private delayer: Delayer<Promise<T>>;
    private throttler: Throttler;

    trigger(promiseFactory: ICancellableTask<Promise<T>>, delay?: number): Promise<T> {
        // Delay execution, then throttle concurrent executions
        return this.delayer.trigger(
            () => this.throttler.queue(promiseFactory), 
            delay
        ) as unknown as Promise<T>;
    }

    dispose(): void {
        this.delayer.dispose();
        this.throttler.dispose();
    }
}
