**AsyncEmitter** - Async event handling with CancellationToken:
```typescript
export class AsyncEmitter<T extends IWaitUntil> extends Emitter<T> {
    async fireAsync(data: IWaitUntilData<T>, token: CancellationToken, promiseJoin?: ...): Promise<void> {
        while (this._asyncDeliveryQueue.size > 0 && !token.isCancellationRequested) {
            const [listener, data] = this._asyncDeliveryQueue.shift()!;
            const thenables: Promise<unknown>[] = [];

            const event = <T>{
                ...data,
                token,
                waitUntil: (p: Promise<unknown>): void => {
                    thenables.push(p);
                }
            };

            listener(event);
            Object.freeze(thenables);
            await Promise.allSettled(thenables);
        }
    }
}
```

**PauseableEmitter** - Pause/resume event delivery:
```typescript
export class PauseableEmitter<T> extends Emitter<T> {
    private _isPaused = 0;
    protected _eventQueue = new LinkedList<T>();
    private _mergeFn?: (input: T[]) => T;

    pause(): void {
        this._isPaused++;
    }

    resume(): void {
        if (this._isPaused !== 0 && --this._isPaused === 0) {
            if (this._mergeFn) {
                if (this._eventQueue.size > 0) {
                    const events = Array.from(this._eventQueue);
                    this._eventQueue.clear();
                    super.fire(this._mergeFn(events));
                }
            } else {
                while (!this._isPaused && this._eventQueue.size !== 0) {
                    super.fire(this._eventQueue.shift()!);
                }
            }
        }
    }

    override fire(event: T): void {
        if (this._size) {
            if (this._isPaused !== 0) {
                this._eventQueue.push(event);
            } else {
                super.fire(event);
            }
        }
    }
}
```

**DebounceEmitter** - Debounced event firing:
